import { useState } from "react";

export default function TodoApp() {
  const [text, setText] = useState("");
  const [filter, setFilter] = useState("all");
  const [todos, setTodos] = useState([]);

  function addTodo() {
    if (!text.trim()) return;

    setTodos([
      ...todos,
      { text, done: false },
    ]);

    setText("");
  }

  function toggle(i) {
    setTodos(
      todos.map((todo, j) =>
        i === j
          ? { ...todo, done: !todo.done }
          : todo
      )
    );
  }

  const visible = todos.filter(todo =>
    filter === "all"
      ? true
      : filter === "active"
      ? !todo.done
      : todo.done
  );

  return (
    <main>
      <h1>📝 Todo</h1>

      <form
        onSubmit={e => {
          e.preventDefault();
          addTodo();
        }}
      >
        <input
          value={text}
          placeholder="New task..."
          onChange={e => setText(e.target.value)}
        />

        <button>Add</button>
      </form>

      <p>
        Show:
        {" "}
        <button disabled={filter === "all"} onClick={() => setFilter("all")}>
          All
        </button>
        {" "}
        <button disabled={filter === "active"} onClick={() => setFilter("active")}>
          Active
        </button>
        {" "}
        <button disabled={filter === "done"} onClick={() => setFilter("done")}>
          Done
        </button>
      </p>

      <p>{todos.filter(todo => !todo.done).length} remaining</p>

      <section>
		{visible.map((todo, i) => (
			<p key={i}>
			<label>
				<input
				type="checkbox"
				checked={todo.done}
				onChange={() => toggle(i)}
				/>
				{todo.done ? <s>{todo.text}</s> : todo.text}
			</label>
			</p>
		))}
		</section>
    </main>
  );
}
